Rule.Source:
import sailpoint.object.Rule;
import sailpoint.object.Script;
import sailpoint.tools.xml.AbstractXmlObject;

var lines = new ArrayList();
var scriptContext = new HashMap();
scriptContext.put("__buffer__", lines);
var ruleLibrary = new Rule();
ruleLibrary.setSource("print(s) { __buffer__.add(s); }");
if ((rulerunnerOutput != void) && (rulerunnerOutput != null))
{
    scriptContext.put("rulerunnerOutput", rulerunnerOutput);
}

var start = System.currentTimeMillis();
var object = context.runScript(new Script(script), scriptContext, List.of(ruleLibrary));
var duration = System.currentTimeMillis() - start;

if ((rulerunnerOutput == void) || (rulerunnerOutput == null))
{
    return lines.isEmpty() ? object : lines;
}

if (!lines.isEmpty())
{
	rulerunnerOutput.printNoEscape("<pre>");
	rulerunnerOutput.print(String.join("\n", lines));
	rulerunnerOutput.printNoEscape("</pre>");
}

if (object != null)
{
	rulerunnerOutput.printNoEscape("<pre>");
	rulerunnerOutput.print((object instanceof AbstractXmlObject) ?
		object.toXml(false) :
		object.toString()
	);
	rulerunnerOutput.printNoEscape("</pre>");
}

rulerunnerOutput.addMessage("%.03f seconds", duration/1000.0);
